messages.content:
CLUSTER:
[
 {
  "riskId": "risk.competitive-foreclosure.framework-agreement-foreclosure-large-operators",
  "title": "The declared first buyer (large operators, 40% of spend) is closed by global framework agreements, not by competition",
  "narrative": "The venture's stated go-to-market is 'sell to large operators first.' But hyperscalers and large colos do not buy rack power in Central Europe — they call off against global, multi-year framework agreements negotiated at HQ with Schneider, Vertiv, Eaton and Legrand. Vertiv's own partner documentation names Equinix, Alibaba, AT&T and Telefonica as direct major customers. A CE entrant in its first 12 months cannot intercept those frameworks locally: vendor qualification cycles at this buyer class run 18–36 months and are gated by approved-vendor lists that open only at framework renewal. The 0.40 buyer cell the whole GTM rests on is not 'hard to win' — for the model's Year-1 window it is contractually unavailable, and the funnel silently treats it as reachable spend.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "Large operators procure rack PDUs through global/annual framework agreements with the incumbent top vendors — Vertiv's major-customer list (Equinix, Alibaba, AT&T, Telefonica) documents direct HQ-level supply relationships that CE regional teams call off against rather than re-tender",
    "refs": [
     "digest:cust-mix#c9",
     "digest:cr3-vendors#c6",
     "ledger:cust.operator-large"
    ]
   },
   {
    "step": "propagation",
    "text": "A pre-launch entrant arrives mid-framework: approved-vendor-list slots do not open within its 12-month horizon, and no source in the corpus documents any local discretionary rack-PDU spend at large operators outside frameworks — the channel-structure data is entirely absent, so nothing in the model gates this cell by contract calendar",
    "refs": [
     "profile:Stage",
     "digest:cust-mix#c3",
     "ledger:cust.operator-large"
    ]
   },
   {
    "step": "model-impact",
    "text": "The 0.40 cust.operator-large share flows through SAM/YAM as winnable at the conservative-ramp pace, but the correct treatment for Year 1 is foreclosure: the cell exits the venture's reachable scope entirely, and the YAM built on 'large operators first' is drawn from spend the venture cannot bid on",
    "refs": [
     "ledger:cust.operator-large",
     "ledger:obtainableFactor",
     "profile:followups.primary-buyer"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Vendor-qualification prerequisites in large-operator RFQs (existing global supply agreement or AVL membership required to bid)",
    "where": "Equinix / Digital Realty / NTT EMEA supplier-onboarding portals and CE colo fit-out tender documents",
    "threshold": "≥3 of first 5 large-operator opportunities disqualify at vendor-list stage before any technical evaluation",
    "updates": "increases"
   },
   {
    "signal": "Incumbent commentary on multi-year hyperscale/colo supply agreements and backlog for rack power",
    "where": "Schneider Electric and Vertiv quarterly earnings calls, order-backlog and framework-win discussion",
    "threshold": "Explicit reference to multi-year rack-power supply commitments covering European capacity additions",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17,
  "distinctByJudge": "The reframe from 'share hard to win' to 'cell contractually closed on a contract calendar' is genuinely hidden by the ledger's share-plus-band representation, as whyMissable argues, and the digest confirms no channel-structure data ever forced the question. Docked one point because 'hyperscalers buy via global frameworks' is reasonably well known to a competent founder in this space, even if its Year-1 modeling consequence is not."
 },
 {
  "riskId": "risk.base-rate-analogy.avl-foreclosure-of-the-large-operator-channel",
  "title": "Approved-vendor-list machinery forecloses the large-operator 40% for the entire Year-1 window",
  "narrative": "The venture's stated first channel is large operators — the biggest cell in the buyer mix at 0.40. But large operators procure rack power through approved-vendor lists, multi-year framework agreements, and reference-install requirements, and every leader list in the corpus names the same 5–7 entrenched suppliers already inside those frameworks. The reference class of industrial entrants into EU DC hardware got in via OEM white-label and distribution, not direct-to-operator. The 0.40 cell itself rests on a single misused datapoint (one supplier's order mix, not a market channel split). The risk is not that this slice is slow — it is that it is structurally closed to a pre-launch entrant for the duration of the YAM window, which means the model's largest customer cell should be removed from reachable scope, not ramped slowly.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "The GTM plan targets large operators first, but these buyers run AVL/framework procurement with reference-install prerequisites, and the incumbent set that populates those AVLs is the same 5–7 vendors across every published leader list",
    "refs": [
     "profile:Primary buyer",
     "digest:cr3-vendors#c6",
     "digest:cr3-vendors#c7"
    ]
   },
   {
    "step": "propagation",
    "text": "A pre-launch entrant with zero installed base cannot satisfy prequalification, so it cannot even enter the tenders that constitute this demand; the 0.40 weight has no evidential basis as entrant-reachable demand — its only evidence is one supplier's company-level order statistic",
    "refs": [
     "ledger:cust.operator-large",
     "digest:cr3-vendors#c5",
     "digest:obtainable-benchmark#c9"
    ]
   },
   {
    "step": "model-impact",
    "text": "The largest customerType cell is unavailable to the venture within the obtainable horizon: SAM as experienced by this entrant excludes the operator-large slice, and Year-1 pipeline built against it converts to zero",
    "refs": [
     "ledger:cust.operator-large",
     "ledger:obtainableFactor"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Prequalification clauses in CE colocation and hyperscale fit-out tenders (reference installs, minimum trading history, framework membership)",
    "where": "Supplier portals of major CE operators (e.g., Equinix, NTT, Vantage EMEA procurement portals) and Frankfurt/Amsterdam fit-out RFQs",
    "threshold": "≥2 of the first 5 relevant RFQs require reference installs or ≥3-year supply track record",
    "updates": "increases"
   },
   {
    "signal": "Where inbound and early pipeline demand actually routes",
    "where": "The venture's own CRM: channel of the first 10 qualified conversations",
    "threshold": ">70% of engaged demand arrives via integrator/OEM/distributor rather than operator direct",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17,
  "distinctByJudge": "Goes beyond 'the 0.40 might be soft' by naming a NEW structural reason: procurement machinery no ledger node represents, plus the finding that the 0.40 rests on one supplier's order mix, not a channel split. A founder knows AVLs exist, so full foreclosure-as-framing is sharp but the general 'big buyers are hard to sell into' skeleton is on most competent lists."
 },
 {
  "riskId": "risk.regulatory-gauntlet.nis2-avl-gate-large-operators",
  "title": "NIS2 supply-chain clauses turn large operators' approved-vendor lists into a security-certification gate the pre-launch entrant cannot pass in Year 1",
  "narrative": "The venture's declared first channel is large operators — the cust.operator-large node at 0.40, itself an unsourced internal estimate. But large CE data-center operators are essential entities under NIS2 (transposing across CE through 2024–26, Germany via the NIS2 implementation act), and Article 21(2)(d) obliges them to manage ICT supply-chain risk. Operationally this arrives as supplier-security questionnaires demanding ISO/IEC 27001 and IEC 62443 evidence for any networked device that touches their management plane — which an intelligent PDU does by definition. A pre-launch entrant holds none of these artifacts. The law never names PDU vendors, so it appears on no vendor risk list; it closes the primary channel anyway, forcing deals through OEM/integrator wrappers at lower margin and slower pace.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "NIS2 transposition makes large DC operators essential entities with legally-mandated supply-chain security duties; procurement operationalizes this as mandatory supplier security certifications (ISO 27001, IEC 62443-4-1/-4-2) for networked equipment on the management network — the category an intelligent PDU sits in",
    "refs": [
     "profile:Product",
     "ledger:cust.operator-large",
     "digest:serviceable-benchmark#c12"
    ]
   },
   {
    "step": "propagation",
    "text": "The 0.40 buyer-mix estimate rests on capacity shares and qualitative channel logic with no evidence of how much large-operator spend sits behind certified approved-vendor lists; a pre-launch entrant with no certification history fails AVL onboarding regardless of product quality, and the sales motion migrates to OEM/integrators whose certifications wrap the product",
    "refs": [
     "ledger:cust.operator-large",
     "ledger:cust.oem",
     "digest:serviceable-benchmark#c13"
    ]
   },
   {
    "step": "model-impact",
    "text": "The large-operator slice reachable by this entrant in Year 1 is materially smaller than the modeled 0.40 — the funnel's largest buyer node overstates the addressable channel for precisely the venture's chosen entry path",
    "refs": [
     "ledger:cust.operator-large",
     "profile:Stage"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Security-certification prerequisites in operator supplier-registration portals",
    "where": "Equinix/NTT/Vantage/Data4 supplier onboarding portals; TED procurement notices for DC fit-outs",
    "threshold": "ISO 27001 or IEC 62443 listed as mandatory for connected facility equipment",
    "updates": "increases"
   },
   {
    "signal": "National NIS2 transposition guidance explicitly covering facility/OT equipment supply chains",
    "where": "BSI (Germany) NIS2 guidance dockets; NCSC-NL publications",
    "threshold": "guidance naming power/facility equipment vendors within supply-chain risk scope",
    "updates": "increases"
   }
  ],
  "judgeTotal": 16,
  "distinctByJudge": "The whyMissable argument is genuine: NIS2 regulates operators not vendors, so a vendor-side regulatory scan misses it and it 'arrives disguised as a procurement questionnaire.' Docked one point because supply-chain security clauses cascading into supplier questionnaires is a known pattern a security-aware founder selling networked devices might anticipate, consistent with the risk's own 'medium' expectedObviousness."
 },
 {
  "riskId": "risk.boundary-substitution.large-operator-channel-forecloses-to-odm",
  "title": "The chosen first buyer — large operators — is migrating PDU procurement into ODM whole-rack deals, moving the decision to a channel the venture doesn't sell through",
  "narrative": "The venture's stated Year-1 route is selling to large operators, and cust.operator-large carries the biggest buyer weight (0.40) — justified in the ledger by hyperscale+colo being ~68% of capacity and large operators 'buying direct'. But direct purchase of discrete PDUs is exactly what large operators are unwinding: AI-density capacity is procured as integrated racks from ODM/rack integrators, where power distribution (shelf or PDU) is a BOM line the integrator sources under multi-year white-label agreements with incumbents. The demand doesn't shrink on paper — it relocates from cust.operator-large (where the venture has a channel plan) into cust.oem (where it has none), and BOM slots there are locked by Schneider/Vertiv/Eaton-class relationships years ahead. For a pre-launch entrant, a slice that moves to a foreclosed channel is functionally not addressable, whatever the buyer-mix pie chart says.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "The venture's primary Year-1 buyer is large operators, whose capacity base (hyperscale 48% + colo 20% of worldwide capacity per Synergy end-2025) underpins the 0.40 weight — and whose new AI-density capacity is procured as ODM-integrated racks rather than component PDUs",
    "refs": [
     "profile:Who is the primary buyer you'll sell through first?",
     "digest:seg-mix#c0",
     "digest:seg-mix#c1",
     "ledger:cust.operator-large"
    ]
   },
   {
    "step": "propagation",
    "text": "When rack power becomes an integrator BOM line, vendor selection shifts to white-label/OEM agreements dominated by the named incumbent set (Schneider at 15.8% plus a 5–7-vendor co-equal leader group per multiple reports); a pre-launch entrant with no ODM qualification cannot contest these slots inside 12 months",
    "refs": [
     "digest:cr3-vendors#c0",
     "digest:cr3-vendors#c6",
     "digest:cr3-vendors#c7",
     "ledger:cust.oem"
    ]
   },
   {
    "step": "model-impact",
    "text": "cust.operator-large's 0.40 is a needs-source internal estimate resting on one misused company-level order stat with zero published channel data; if a material fraction of large-operator PDU spend flows through integrator channels, the direct-sale pool the venture's entire Year-1 motion targets is overstated — YAM's obtainable assumption is applied to a pool that partly is not there",
    "refs": [
     "ledger:cust.operator-large",
     "ledger:cust.oem",
     "ledger:obtainableFactor"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Procurement structure in large-operator capacity programs (discrete PDU RFQs vs integrated rack packages)",
    "where": "TED (EU tender platform) for operator framework agreements; Equinix/Digital Realty/NTT procurement supplier-onboarding portals and capex call commentary",
    "threshold": "A major CE operator consolidating rack power into an integrated-rack or fit-out-contractor package for the first time",
    "updates": "increases"
   },
   {
    "signal": "ODM/integrator rack-scale revenue and PDU white-label announcements",
    "where": "OCP Global Summit sponsor/deployment talks; Foxconn/Quanta/Wiwynn investor updates on rack-scale system revenue; Legrand/Vertiv OEM-agreement press releases",
    "threshold": "Rack-scale integrated systems revenue at major ODMs growing >30% YoY with named European deployments",
    "updates": "increases"
   }
  ],
  "judgeTotal": 18,
  "distinctByJudge": "The whyMissable field correctly identifies that the team's needs-source flag would drive them to validate the 0.40 number, while the actual risk is the category boundary (direct-buy vs integrated-rack) moving during the entry window — a new reason, not a band-edge claim. Docked one point because ODM rack integration for AI capacity is a widely reported industry trend a well-read founder might connect."
 },
 {
  "riskId": "risk.execution-window.avl-gate-forecloses-large-operator-channel",
  "title": "The Year-1 primary channel sits behind an approved-vendor-list gate that pre-launch entrants historically cannot open in 12 months",
  "narrative": "The venture's stated go-to-market is 'large operators first', and the funnel gives that buyer 40% of PDU spend. But large CE operators procure rack power through approved-vendor lists whose onboarding — factory audit, firmware security review, reference installs, dual-region logistics — is a qualification cycle, not a sales cycle. The incumbent lock is visible in Vertiv's named major-customer roster (Equinix, Telefonica, Vodafone). For a pre-launch entrant, the 0.40 slice is not 'ours to win slowly'; it is procedurally unreachable inside the model's Year-1 clock, and the YAM is keyed on exactly this buyer. The reachable Year-1 mix is the distributor/OEM tail the plan hasn't built.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "Large-operator procurement requires AVL qualification (security audit, factory audit, references) that a pre-launch vendor cannot present on day 1; incumbents already hold these slots per Vertiv's named large-account roster",
    "refs": [
     "digest:cust-mix#c9",
     "profile:Stage",
     "ledger:cust.operator-large"
    ]
   },
   {
    "step": "propagation",
    "text": "The 0.40 buyer-mix figure rests on a misread company-level order stat, not a channel study — nothing in it encodes time-to-qualify; meanwhile the indirect channels that ARE open to a new entrant (master distributor, OEM white-label) carry only 0.13 and 0.22 in the mix",
    "refs": [
     "digest:cust-mix#c0",
     "digest:cust-mix#c8",
     "ledger:cust.distributor",
     "ledger:cust.oem"
    ]
   },
   {
    "step": "model-impact",
    "text": "The large-operator cell is foreclosed for the Year-1 window: excluding cust.operator-large removes the largest buyer slice from reachable scope and the YAM built on it, rather than merely shrinking it",
    "refs": [
     "ledger:cust.operator-large",
     "ledger:obtainableFactor"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Stated supplier-onboarding lead time and prerequisites (audits, references, insurance) for new hardware vendors",
    "where": "Equinix, Digital Realty and Vantage EMEA supplier-registration portals; procurement annexes in TED-listed DC fit-out tenders",
    "threshold": ">6 months from registration to RFQ eligibility, or mandatory reference installs",
    "updates": "increases"
   },
   {
    "signal": "Preferred-vendor or sole-source language for rack power at large CE accounts",
    "where": "Vertiv/Schneider EMEA partner-program documents and quarterly earnings commentary on framework agreements",
    "threshold": "Multi-year rack-power frameworks announced at ≥2 flagship CE operators",
    "updates": "increases"
   }
  ],
  "judgeTotal": 16,
  "distinctByJudge": "The 0.40 slice is in the model, but the risk supplies a NEW reason: the ledger has no time-to-qualify node and the mix figure 'rests on a misread company-level order stat', so no sensitivity band exposes it. Loses a point because 'large-account procurement is slow for new vendors' is on most competent founders' lists; the novel part is the exclude-vs-shrink framing."
 },
 {
  "riskId": "risk.ledger-self-audit.buyer-mix-fabricated-odm-leakage",
  "title": "The 0.40 'large operators buy direct' share is one misread order-book stat — and the corpus says the real large-operator volume flows through ODM white-label the entrant can't intercept",
  "narrative": "The venture's stated go-to-market is 'large operators first', and the model rewards that with a 0.40 customer-type slice. But the only attached evidence for 0.40 is a company-level statistic (one supplier's DC orders = 30% of its book) that says nothing about buyer channels, and cust.oem/distributor carry zero evidence. Meanwhile the same digest documents the actual structure: hyperscale and large-colo procurement increasingly runs through Taiwanese ODM/white-label programs (Digipower, GETEKnet) and master distributors — spend that is nominally 'large operator' but contractually locked into OEM design-win cycles a pre-launch EU brand cannot enter in Year 1. The largest customer node isn't just uncertain; it is partly not a channel this entrant can address at all.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "cust.operator-large's 0.40 rests on a single order-mix datapoint (DC = 30% of one supplier's orders) misused as a market channel split; no source publishes any numeric buyer-channel breakdown",
    "refs": [
     "digest:cust-mix#c0",
     "ledger:cust.operator-large"
    ]
   },
   {
    "step": "propagation",
    "text": "Documented ODM/white-label supply (Digipower serving 'global OEM partners and infrastructure operators', GETEKnet as explicit OEM rack-PDU supplier, distributors offering private-label) means a material fraction of large-operator PDU volume is procured as white-label design wins with multi-year qualification cycles, not open branded tenders",
    "refs": [
     "digest:cust-mix#c11",
     "digest:cust-mix#c12",
     "digest:cust-mix#c13",
     "digest:cust-mix#c8"
    ]
   },
   {
    "step": "model-impact",
    "text": "The direct-branded large-operator slice shrinks (0.40→~0.27) while the OEM/integrator slice grows — but grows in a channel where a pre-launch entrant competes on ODM economics and 18–24 month qualification, so the venture's declared primary channel overstates its Year-1 reachable spend",
    "refs": [
     "ledger:cust.operator-large",
     "ledger:cust.oem",
     "profile:Who is the primary buyer you'll sell through first?"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "PDU specification language in large CE operator RFQs — 'ODM/white-label per our spec' vs open branded procurement",
    "where": "Hyperscaler supplier-registration portals and Frankfurt/Amsterdam colocation fit-out RFQ packages",
    "threshold": "≥2 of first 5 target accounts procuring PDUs exclusively via ODM programs or rack-integrator bundles",
    "updates": "increases"
   },
   {
    "signal": "Channel-mix commentary from incumbents — direct vs partner revenue split in EMEA",
    "where": "Vertiv EMEA partner-program materials and quarterly earnings channel commentary; Schneider partner announcements",
    "threshold": "Incumbents reporting growing share of rack-power revenue via integrator/ODM programs",
    "updates": "increases"
   },
   {
    "signal": "Rack-level pre-integration announcements (PDUs shipped pre-installed in integrated racks)",
    "where": "OCP summit talks and rack-integrator (system-build) press releases for CE deployments",
    "threshold": "Pre-integrated racks specified in ≥2 flagship CE builds",
    "updates": "increases"
   }
  ],
  "judgeTotal": 16,
  "distinctByJudge": "This is not 'the 0.40 might be low' — it names a NEW reason: the sole attached evidence is a company order-book stat answering a different question, and the volume is contractually routed through ODM design-win cycles the entrant cannot enter. The whyMissable is credible (the four shares sum to 1.00 and mirror capacity mix), though a diligent founder tracing evidence provenance might catch the misused stat."
 },
 {
  "riskId": "risk.demand-discontinuity.large-operator-qualification-tunnel",
  "title": "'Large operators first' aims the launch at the one channel that cannot buy inside 12 months",
  "narrative": "The venture's stated first channel is large operators — and the model rewards that choice with the biggest buyer node (0.40, the widest-swing customer share). But that 0.40 is an internal estimate resting on a single misread order-mix statistic, and it says nothing about ACCESS. Large colo and hyperscale operators buy rack power through approved-vendor lists and framework agreements: qualification (CE/TÜV, EN 50600 alignment, firmware security review, DCIM interoperability, pilot pods) routinely runs 12–24 months for a new hardware vendor. For a pre-launch entrant, the large-operator slice is not a smaller number — it is unavailable inside the YAM window. Year-1 reachable demand collapses onto OEM/integrator and distributor channels the model weights at only 0.35 combined and has never validated.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "The go-to-market plan names large operators as the first buyer, and the model assigns them the dominant 0.40 buyer share — a share whose only evidence is one supplier's company-level order mix, with the ledger itself flagging 'internal estimate, no published channel split'",
    "refs": [
     "profile:Stage",
     "ledger:cust.operator-large"
    ]
   },
   {
    "step": "propagation",
    "text": "Large operators' near-term deliveries are pre-let (83%) and vendor-committed under frameworks with a semi-consolidated incumbent set (CR3 ~0.55); a new vendor must first clear AVL qualification, which for powered rack hardware exceeds the venture's entire 12-month horizon — so the channel is sequentially blocked, not just competitive",
    "refs": [
     "digest:geo-DE#c21",
     "ledger:shape.cr3"
    ]
   },
   {
    "step": "model-impact",
    "text": "Within the YAM window the operator-large cell is foreclosed: Year-1 obtainable demand must route through OEM/integrator (0.22) and distributor (0.13) cells — both zero-evidence estimates — shrinking reachable SAM by the excluded share",
    "refs": [
     "ledger:cust.oem",
     "ledger:cust.distributor",
     "ledger:cust.operator-large"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Stated vendor-qualification requirements and timelines in operator supplier onboarding portals",
    "where": "Equinix, NTT GDC, Data4, Vantage supplier/procurement portals and RFQ documents",
    "threshold": "Mandatory qualification stages summing to >9 months before first PO eligibility",
    "updates": "increases"
   },
   {
    "signal": "Venture's own qualification funnel progress with the first two target operators",
    "where": "Internal CRM / operator procurement correspondence, reviewed monthly",
    "threshold": "No pilot-pod agreement signed within 4 months of launch",
    "updates": "increases"
   },
   {
    "signal": "Distributor and rack-integrator line-card openings for third-party intelligent PDUs",
    "where": "CE electrical distributor price lists (Rexel, Sonepar) and rack-integrator OEM programs",
    "threshold": "≥1 CE distributor actively onboarding a new PDU brand",
    "updates": "decreases"
   }
  ],
  "judgeTotal": 16,
  "distinctByJudge": "The core insight — that channel size and channel entry speed are different variables and the model only encodes the first ('the size of a channel and the speed of entry into it are different variables') — reframes the largest node as foreclosed rather than merely uncertain, and adds the wrinkle that Year-1 demand collapses onto the zero-evidence 0.35 indirect cells. However, long enterprise-hardware qualification cycles are known territory for experienced hardware founders, so it falls short of 'would never have it on their list'."
 },
 {
  "riskId": "risk.structure-independence.global-framework-forecloses-large-operator-cell",
  "title": "Global framework agreements foreclose the large-operator channel — the venture's declared first buyer — from a CE entry point",
  "narrative": "The model gives large operators 0.40 of buyer spend, and the venture plans to sell to them first. But hyperscalers and pan-European colos (Equinix, Digital Realty — exactly the accounts on Vertiv's published major-customer list) qualify rack-PDU vendors on global framework agreements and approved-vendor lists negotiated at HQ on multi-year cycles. That spend is not addressable from a Central European regional sales motion in a 12-month window; it is not 'ours to win slowly', it is contractually and organizationally elsewhere. The 0.40 itself rests on a misread company-level order-mix statistic, not any channel data. The venture's GTM points at the one cell of the cube that is structurally closed to it.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "Large-operator PDU procurement runs through global AVLs and framework agreements: Vertiv's named major customers are the global hyperscale/colo/telecom accounts, and industrial suppliers report data-center demand concentrating in exactly these buyers",
    "refs": [
     "digest:cust-mix#c9",
     "digest:cust-mix#c0"
    ]
   },
   {
    "step": "propagation",
    "text": "The 0.40 large-operator share has no channel evidence behind it — its sole datapoint is one supplier's 30%-of-orders stat, and no source publishes any numeric buyer-channel split — so the model cannot distinguish 'large operators buy 40% of PDUs' from 'large operators buy 40% of PDUs via global frameworks a CE entrant cannot bid into'",
    "refs": [
     "ledger:cust.operator-large",
     "digest:cust-mix#c0"
    ]
   },
   {
    "step": "model-impact",
    "text": "For this venture's reachable scope, the large-operator cell is foreclosed rather than merely competitive; the declared first-buyer strategy targets it anyway, so SAM and Year-1 pipeline are built on a cell the funnel counts but the venture cannot access",
    "refs": [
     "profile:Who is the primary buyer you'll sell through first?",
     "ledger:cust.operator-large"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Vendor-qualification and supplier-registration requirements for rack power at pan-European colos",
    "where": "Equinix and Digital Realty supplier/procurement portals; framework tender notices on TED (tenders.europa.eu) for DC fit-outs",
    "threshold": "PDU category listed only under global framework agreements with no regional qualification path",
    "updates": "increases"
   },
   {
    "signal": "Where incumbent PDU wins at large accounts are booked",
    "where": "Vertiv and Schneider quarterly earnings calls, commentary on hyperscale framework awards",
    "threshold": "Rack-power growth attributed predominantly to global framework expansions rather than regional project wins",
    "updates": "increases"
   }
